PyTypeObject* DoInitWrapperQuat(const UScriptStruct* InStruct, PyTypeObject* InSuperType)
{
	if (InStruct == nullptr)
	{
		return nullptr;
	}

	if (FUPyWrapperTypeRegistry::Get().HasWrappedStructType(InStruct))
	{
		return const_cast<PyTypeObject*>(FUPyWrapperTypeRegistry::Get().GetWrappedStructType(InStruct));
	}

	PyTypeObject* PyType = &UPyWrapperQuatType;
	PyType->tp_flags = Py_TPFLAGS_DEFAULT | Py_TPFLAGS_BASETYPE;
	PyType->tp_base = InSuperType != nullptr ? InSuperType : &UPyWrapperStructType;
	PyType->tp_init = (initproc)&FFuncs_Quat::Init;
	PyType->tp_methods = FUPyWrapperQuatPyMethodDefs;
	PyType->tp_getset = FUPyWrapperQuatGetSets;
	static PyNumberMethods PyNumber;
	PyNumber.nb_add = (binaryfunc)&FNumberFuncs_Quat::Op_add;
	PyNumber.nb_inplace_add = (binaryfunc)&FNumberFuncs_Quat::Op_iadd;
	PyNumber.nb_inplace_multiply = (binaryfunc)&FNumberFuncs_Quat::Op_imul;
	PyNumber.nb_inplace_subtract = (binaryfunc)&FNumberFuncs_Quat::Op_isub;
	PyNumber.nb_multiply = (binaryfunc)&FNumberFuncs_Quat::Op_mul;
	PyNumber.nb_subtract = (binaryfunc)&FNumberFuncs_Quat::Op_sub;
	PyType->tp_as_number = &PyNumber;

	if (PyType_Ready(PyType) == 0)
	{
		FUPyConstantDef::AddConstantsToType(FConstants_Quat::Table(), PyType);
		FUPyWrapperTypeRegistry::Get().RegisterWrappedStructType(InStruct, PyType);
		return PyType;
	}

	return nullptr;

}

void InitializeUPyWrapperQuat(UPyGenUtil::FNativePythonModule& ModuleInfo)
{
	FUPyWrapperTypeRegistry::Get().RegisterInlineStructFactory(StaticCastSharedRef<const IUPyWrapperInlineStructFactory>(MakeShared<TUPyWrapperInlineStructFactory<FQuat>>()));
	FUPyWrapperTypeRegistry::Get().RegisterAutoWrappedStructCreateFunc(TBaseStructure<FQuat>::Get(), DoInitWrapperQuat);
}

PyObject* FUPyWrapperQuat::CreateInstance(const FQuat& InValue, const FUPyWrapperOwnerContext& InOwnerContext, const EUPyConversionMethod InConversionMethod)
{
	return (PyObject*)FUPyWrapperStructFactory::Get().CreateInstance(&UPyWrapperQuatType, TBaseStructure<FQuat>::Get(), (void*)&InValue, InOwnerContext, InConversionMethod);
}

FUPyWrapperQuat* UPyIsQuat(PyObject* InSelf)
{
	if (InSelf && PyObject_TypeCheck(InSelf, &UPyWrapperQuatType))
	{
		return (FUPyWrapperQuat*)InSelf;
	}
	return nullptr;
}

namespace UPyConversion
{
	FUPyConversionResult NativizeStructInstance(PyObject* PyObj, FQuat& OutVal, const ESetErrorState SetErrorState)
	{
		if (FUPyWrapperQuat* PyVector = UPyIsQuat(PyObj))
		{
			OutVal = *PyVector->ValuePtr();
			return FUPyConversionResult::Success();
		}

		UPYCONVERSION_RETURN(FUPyConversionResult::Failure(), TEXT("NativizeStructInstance"), *FString::Printf(TEXT("Cannot nativize '%s' as 'FQuat'"), *UPyUtil::GetFriendlyTypename(PyObj)));
	}
	
	FUPyConversionResult PythonizeStructInstance(const FQuat& InVal, PyObject*& OutPyObj, const ESetErrorState SetErrorState)
	{
		OutPyObj = FUPyWrapperQuat::CreateInstance(InVal, FUPyWrapperOwnerContext(), EUPyConversionMethod::Copy);
		return FUPyConversionResult::Success();
	}
}
